            img: "images/lunch menu/saikyouyaki.png",
            description: "奥深い味わい！\nじっくり漬け込んだ特製西京焼。",
            price: 1500
        },
        {
            id: "sabamisoni",
            name: "鯖味噌煮定食", 
            img: "images/lunch menu/sabamisoni.png",
            description: "王道の味！\n身体に染みわたる濃厚さば味噌煮定食。",
            price: 1200
        },
        {
            id: "butakakuni",
            name: "豚角煮定食", 
            img: "images/lunch menu/butakakuni.png",
            description: "じっくり煮込み！極上の柔らかさ角煮定食。",
            price: 1400
        }
    ]
};

document.addEventListener('DOMContentLoaded', function() {
    // menuData is now in data.js

    const menuContainer = document.getElementById('menu');

    for (const category in menuData) {
        const categorySection = document.createElement('section');
        categorySection.classList.add('category');

        const categoryTitle = document.createElement('h2');
        categoryTitle.classList.add('category-title');
        categoryTitle.textContent = category;
        categorySection.appendChild(categoryTitle);

        const itemsGrid = document.createElement('div');
        itemsGrid.classList.add('menu-items-grid');

        menuData[category].forEach(item => {
            // Create a link for each item
            const menuLink = document.createElement('a');
            menuLink.href = `detail.html?item=${item.id}`;
            menuLink.classList.add('menu-item-link'); // Add a class for styling

            const menuItem = document.createElement('div');
            menuItem.classList.add('menu-item');

            const itemImage = document.createElement('img');
            itemImage.src = item.img;
            itemImage.alt = item.name;
            menuItem.appendChild(itemImage);

            const itemDetails = document.createElement('div');
            itemDetails.classList.add('menu-item-details');

            const itemName = document.createElement('h3');
            itemName.classList.add('menu-item-name');
            itemName.textContent = item.name;
            itemDetails.appendChild(itemName);

            menuItem.appendChild(itemDetails);

            // Append the item to the link, and the link to the grid
            menuLink.appendChild(menuItem);
            itemsGrid.appendChild(menuLink);
        });

        categorySection.appendChild(itemsGrid);
        menuContainer.appendChild(categorySection);
    }
});

/* Basic Reset & Body Style */
html, body {
    min-height: 100vh;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, "Noto Sans", sans-serif;
    margin: 0;
    padding: 0;
    background: url('images/taitoru-haikei/IMG_0055.jpg') no-repeat center center fixed;
    background-size: cover;
    color: #333;
}

/* Header */
header {
    background: url('images/taitoru-haikei/sengyo.jpg') no-repeat center center;
    background-size: cover;
    color: white;
    padding: 20px;
    text-align: center;
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
}

header::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.5);
}

/* Logo */
.logo {
    width: 80px;
    height: 80px;
    margin-bottom: 10px;
    position: relative;
    z-index: 1;
}

header h1, header p {
    position: relative;
    z-index: 1;
}

header h1 {
    margin: 0;
    font-size: 2.5em;
    font-weight: bold;
    text-shadow: 2px 2px 4px rgba(0,0,0,0.7);
}

header p {
    margin: 5px 0 0;
    font-size: 1.2em;
    text-shadow: 1px 1px 2px rgba(0,0,0,0.7);
}

/* Tagline */
.tagline {
    position: relative;
    z-index: 1;
    margin-top: 10px;
}

.tagline p {
    margin: 2px 0;
    font-size: 0.67em;
    letter-spacing: 0.1em;
    text-shadow: 1px 1px 2px rgba(0,0,0,0.7);
}

/* Menu Container */
#menu {
    padding: 10px;
}

/* Category Section */
.category {
    margin-bottom: 30px;
}

.category-title {
    font-size: 1.8em;
    font-weight: bold;
    text-align: center;
    border-bottom: 3px solid #d3a26c; /* A nice golden color */
    color: #fff; /* Change text to white */
    text-shadow: 2px 2px 4px rgba(0,0,0,0.7); /* Add shadow for readability */
    background-color: rgba(0, 0, 0, 0.3); /* Add a subtle dark background */
    padding: 10px 0;
    margin-bottom: 20px;
    border-radius: 5px;
}

/* Menu Items Grid */
.menu-items-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    gap: 15px;
}

/* To remove default link styles from menu items */
.menu-item-link {
    text-decoration: none;
    color: inherit;
}

/* Menu Item */
.menu-item {
    background-color: #fff;
    border-radius: 8px;
    box-shadow: 0 4px 8px rgba(0,0,0,0.08);
    overflow: hidden;
    text-align: center;
    transition: transform 0.2s ease-in-out;
}

.menu-item:hover {
    transform: translateY(-5px);
}

.menu-item img {
    width: 100%;
    height: 120px;
    object-fit: cover;
}

.menu-item-details {
    padding: 10px;
}

.menu-item-name {
    font-size: 1em;
    font-weight: 600;
    margin: 0;
}

/* For smaller screens, maybe 1 column */
@media (max-width: 360px) {
    .menu-items-grid {
        grid-template-columns: 1fr;
    }
}

/* Detail Page Styles */
.detail-container {
    padding: 20px;
    max-width: 600px;
    margin: 0 auto;
}

.detail-container img {
    width: 100%;
    height: 400px; /* Set a fixed height */
    object-fit: cover; /* Crop the image to fit, maintaining aspect ratio */
    border-radius: 8px;
    margin-bottom: 20px;
}

.detail-text-content {
    background-color: #fff;
    border-radius: 8px;
    padding: 20px;
    box-shadow: 0 4px 8px rgba(0,0,0,0.08);
}

.detail-container h1 {
    font-size: 2em;
    margin-bottom: 10px;
}

.detail-container #detail-desc {
    font-size: 1.1em;
    line-height: 1.6;
    text-align: justify;
    white-space: pre-line;
}

.back-link {
    display: inline-block;
    margin-bottom: 20px;
    text-decoration: none;
    color: #333;
    font-weight: bold;
}

/* Price Style on Detail Page */
.price {
    font-size: 1.5em;
    font-weight: bold;
    color: #d3a26c; /* Use the same golden color as the category border */
    margin-bottom: 20px;
    text-align: right;
}

/* Centering for detail page on mobile */
@media (max-width: 600px) {
    .detail-container {
        text-align: center;
    }
}

